import sys

class MinStack:
    def __init__(self):
        self.stack = []
        self.min_stack = []

    def push(self, val: int) -> None:
        self.stack.append(val)
        if not self.min_stack or val <= self.min_stack[-1]:
            self.min_stack.append(val)

    def pop(self) -> int:
        if self.stack:
            if self.stack[-1] == self.min_stack[-1]:
                self.min_stack.pop()
            return self.stack.pop()

    def top(self) -> int:
        if self.stack:
            return self.stack[-1]

    def getMin(self) -> int:
        if self.min_stack:
            return self.min_stack[-1]

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        n = int(next(it))
    except StopIteration:
        sys.exit(0)
    sol = MinStack()
    output = []
    for _ in range(n):
        op = next(it)
        if op == 'push':
            val = int(next(it))
            sol.push(val)
        elif op == 'pop':
            sol.pop()
        elif op == 'top':
            output.append(str(sol.top()))
        elif op == 'getMin':
            output.append(str(sol.getMin()))
    print('\n'.join(output))

