#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class MinStack {
public:
    stack<int> s;
    stack<int> min_s;

    void push(int val) {
        s.push(val);
        if (min_s.empty() || val <= min_s.top()) {
            min_s.push(val);
        }
    }

    int pop() {
        if (s.empty()) return -1;
        int val = s.top();
        s.pop();
        if (val == min_s.top()) {
            min_s.pop();
        }
        return val;
    }

    int top() {
        if (s.empty()) return -1;
        return s.top();
    }

    int getMin() {
        if (min_s.empty()) return -1;
        return min_s.top();
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    MinStack sol;
    vector<string> output;
    for (int i = 0; i < n; i++) {
        string op;
        if (!(cin >> op)) return 0;
        if (op == "push") {
            int val;
            if (!(cin >> val)) return 0;
            sol.push(val);
        } else if (op == "pop") {
            sol.pop();
        } else if (op == "top") {
            output.push_back(to_string(sol.top()));
        } else if (op == "getMin") {
            output.push_back(to_string(sol.getMin()));
        }
    }
    for (int i = 0; i < output.size(); i++) {
        cout << output[i] << (i == output.size() - 1 ? "" : "\n");
    }
    cout << endl;
    return 0;
}
